import{_ as a,o as l,c as n,a as o,U as s}from"./chunks/framework.2a013da7.js";const p="/assets/20220428165634.7a3efeb5.png",e="/assets/20211008163417.102c5c7b.png",t="/assets/20211008164017.1f6c2119.png",r="/assets/202301121029498.a9fb9500.png",c="/assets/84c1462ff35d42648c0ad5c5bb1bc74a~tplv-k3u1fbpfcp-zoom-in-crop-mark_1512_0_0_0.191eb7fe.webp",i="/assets/06bd3c37896a4fa3ac6595f9c1a181b6~tplv-k3u1fbpfcp-zoom-in-crop-mark_1512_0_0_0.96080a7d.webp",D="/assets/urlencoded.d7ddbfe1.png",y="/assets/202301122010888.6d13ecea.png",F="/assets/202301122046532.8e1d6784.png",C="/assets/Referrer-Policy.d66bd1ea.png",u="/assets/daiLi.84ac1d2c.png",d="/assets/daiLi2.d2974b3b.png",A="/assets/clickJack.8628c6df.png",_=JSON.parse('{"title":"网络","description":"","frontmatter":{},"headers":[],"relativePath":"skill/网络.md","filePath":"skill/网络.md","lastUpdated":1691570100000}'),h={name:"skill/网络.md"},m=s('<h1 id="网络" tabindex="-1">网络 <a class="header-anchor" href="#网络" aria-label="Permalink to &quot;网络&quot;">​</a></h1><p>在网络层面，对于前端开发者，必须要知道浏览器拥有的两大核心能力：</p><ul><li>自动发出请求的能力</li><li>自动解析响应的能力</li></ul><p>当发送GET请求时，浏览器不会附带请求体</p><ol><li>GET 请求只能传递 ASCII 数据，遇到非 ASCII 数据需要进行编码；POST 请求没有限制</li><li>POST 不会被保存到浏览器的历史记录中</li><li>刷新页面时，若当前的页面是通过 POST 请求得到的，则浏览器会提示用户是否重新提交。若是 GET 请求得到的页面则没有提示。</li></ol><p>自动解析响应的能力</p><ol><li>浏览器能够自动识别响应码，当出现一些特殊的响应码时浏览器会自动完成处理，比如301( 永久 重定向 )、302( 临时重定向 )</li><li>根据响应结果做不同的处理浏览器能够自动分析响应头中的Content-Type，根据不同的值进行不同处理，比如：</li></ol><ul><li>text/plain: 普通的纯文本，浏览器通常会将响应体原封不动的显示到页面上</li><li>text/html：html文档，浏览器通常会将响应体作为页面进行渲染</li><li>text/javascript或application/javascript：js代码，浏览器通常会使用JS执行引擎将它解析执行</li><li>text/css：css代码，浏览器会将它视为样式</li><li>image/jpeg：浏览器会将它视为jpg图片</li><li>application/octet-stream：二进制数据，会触发浏览器下载功能</li><li>attachment：附件，会触发下载功能该值和其他值不同，应放到Content-Disposition头中。</li></ul><img src="'+p+'"><h2 id="传输" tabindex="-1">传输 <a class="header-anchor" href="#传输" aria-label="Permalink to &quot;传输&quot;">​</a></h2><ul><li><p>应用层</p><ul><li>两个软件可以通过网络通信，那么这两个软件就是应用层</li><li>应用层有很多协议 <ul><li><code>HTTP</code></li><li><code>FTP(文件传输)</code></li><li><code>DNS协议(域名解析)</code></li><li>SMTP协议(邮件传输)<br> 这些协议类似于包装层的方案选择什么来装鱼，黑色袋子、麻袋、还是揣兜里，用于处理不同的场景</li></ul></li></ul></li><li><p>传输层</p><ul><li><strong>传输层主要是保证消息的可靠传递</strong></li><li>传输层协议 <ul><li>UDP协议(User Datagram Protocol,用户数据报协议)</li><li>TCP协议(Transmission Control Protocol,传输控制协议)</li></ul></li></ul></li><li><p>网络层</p><ul><li>IP(Internet Protocol)协议 <ul><li>网络层会接收到来自传输层的“数据”，然后将这些数据拆分很多片段，主要是为了方便IP数据包的发送，理论上每个数据包最多可以存储64KB，但实际上数据包不超过1500个字节，IP路由器会转发每一个数据包，沿着一条路径从一台路由器传递到下一台路由器，直到达到目的地，然后会在<strong>网络层重组</strong>，因为数据是有一个封装和解封装的过程</li></ul></li></ul></li><li><p>数据链路层</p><ul><li>数据链路层的代表就是MAC协议(medium access control,介质访问控制)</li></ul><p>MAC地址相当于我们的身份证号，无论我们在哪个城市，它都是唯一不变的，而IP地址换个城市就会变</p></li><li><p>物理层<br> 二进制数据可以用光纤、双绞线、同轴电缆、电力线等等，像这些传输的介质我们一般称为导向的传输介质</p></li></ul><hr><img src="'+e+'"><img src="'+t+'"><img src="'+r+'"><h2 id="tcp" tabindex="-1">TCP <a class="header-anchor" href="#tcp" aria-label="Permalink to &quot;TCP&quot;">​</a></h2><h3 id="三次握手-四次挥手" tabindex="-1">三次握手,四次挥手 <a class="header-anchor" href="#三次握手-四次挥手" aria-label="Permalink to &quot;三次握手,四次挥手&quot;">​</a></h3><h4 id="三次握手" tabindex="-1">三次握手 <a class="header-anchor" href="#三次握手" aria-label="Permalink to &quot;三次握手&quot;">​</a></h4><p>当发送的数据过大时，会被分成一段一段的数据报，每一段数据报头部都会有TCP头部，这里面包含了很多信息，其中就有上图中的 <strong><code>SYN(Synchronize Sequence Numbers,同步序列编号，是连接建立的握手信号)</code></strong>, <strong><code>seq(sequence，数据报序号)</code></strong>,<strong><code>ACK(Acknowledge character，确认字符，只有0和1)</code></strong>, <strong><code>seq(下次应该发送的编号)</code></strong></p><ol><li>每个链接都是从CLOSED状态开始的，当它执行一个主动打开连接操作或者被动打开连接操作，它就离开了CLOSED状态</li><li>当客户端A向服务器B发送消息的时候，链接从CLOSED状态进入SYN-SENT状态 <ol><li>TCP头部携带SYN=1表示 A 要跟 B 建立同步链接、seq=x表示这次发送的是序号为x的数据报、ACK=0表示还未被确认的数据报，将这三个同时发给B，</li></ol></li><li>B成功收到消息后，CLOSED状态关闭并进入SYN-RCVD状态，表示 <strong>🔥第一次握手成功</strong>，</li><li>此时 B 知道 A 具有发送消息的功能，但不知道的是A是否有接收信息的功能</li><li>这时 B 开始发送消息，<strong>🔥第二次握手发生了</strong>，B的回信 携带TCP头部的信息SYN=1表示我要跟 A 建立同步链接，seq=y表示这次发送的是序号为y的数据报、ACK=1表示 A 的信被确认的数据报, <em>ack=x+1 表示序号为x的数据报已经收到，麻烦下次给我发x+1序号的数据报</em></li><li>A 知道 B 可以收到自己的消息，但是 B 并不知道 A 已经收到自己的消息，所以 A 需要再次发送消息告诉 B，<strong>🔥这时第三次握手发生了</strong>，</li><li>B 知道 A 可以收到自己的消息，此时 A 和 B 双方都具有寄信和收信的能力，这一刻AB的连接就建立成功了，连接状态就变成ESTAB-LISHED，表示正常的传输状态，可以互相交流了。😘</li></ol><h4 id="连接销毁-四次挥手" tabindex="-1">连接销毁（四次挥手） <a class="header-anchor" href="#连接销毁-四次挥手" aria-label="Permalink to &quot;连接销毁（四次挥手）&quot;">​</a></h4><ol><li>当 A 发送消息给 B：&quot;结束链接,是否还有数据&quot;，<strong>🚀这就是第一次挥手</strong>，无论是客户端，还是服务端，都可以发起第一次挥手，我们暂且称为发送方，每一次请求都需要被确认才可以，所以当发送方发起第一次挥手时，发完并不会立刻就挂，而是要等接收方的回应。</li><li>B 收到了 A 的消息，随后回复：“还有数据”，<strong>🚀这就是第二次挥手</strong></li><li>然后 B 发送数据,等 B 发送所有的数据之后,发送：“断开链接”，<strong>🚀这是第三次挥手</strong></li><li>B 也并不知道 A 是否收到，所以 A 依然还需要进行回复：“断开链接” <strong>🚀这是第四次挥手</strong></li></ol><h2 id="http-缓存" tabindex="-1">HTTP 缓存 <a class="header-anchor" href="#http-缓存" aria-label="Permalink to &quot;HTTP 缓存&quot;">​</a></h2><blockquote><p>当客户端发出一个GET请求到服务器,如果一个资源很少变动,可以直接缓存,像那些图片、CSS、JS等资源文件可使用缓存</p></blockquote><img src="'+c+'"><p>服务器设置一个请求头:</p><ul><li>Cache-Control: max-age=31536000 <blockquote><p>我希望你可以把这个资源缓存起来，缓存时间为31636000秒（365天）</p></blockquote></li><li>Date: Thu, 07 Jul 2022 21:35:20 GMT <blockquote><p>我给你响应这个资源的服务器时间是格林威治时间2022-07-07 21:35:20，如果缓存的时间是365天，那就是在此时间上加上365天</p></blockquote></li><li>Etag: W/&quot;3be5f29ac3de039909660e93e1ca5912&quot; <blockquote><p>这个资源编号是 W/&quot;3be5f29ac3de039909660e93e1ca5912&quot;</p></blockquote></li><li>Last-Modified: Tue, 05 Jul 2022 15:09:26 GMT <blockquote><p>这个资源上一次修改时间是格林威治时间 2022-07-05 15:09:26</p></blockquote></li></ul><p>浏览器:</p><ul><li>浏览器会将这次请求得到的响应体缓存在本地文件中</li><li>浏览器会记录这次请求的请求方法和请求路径</li><li>浏览器会记录本次缓存时间是31536000秒</li><li>浏览器会记录服务器响应时间是格林威治时间2022-07-07 21:35:20</li><li>浏览器会记录服务器给予的资源编号是W/&quot;3be5f29ac3de039909660e93e1ca5912&quot;</li><li>浏览器会记录上一次资源修改的时间是格林威治时间 2022-07-05 15:09:26</li></ul><p>请求:</p><ol><li><p>首先会判断有没有匹配的缓存,没有就是普通请求</p></li><li><p>有缓存</p><ol><li>缓存没有过期 <ul><li><p>没有过期,使用缓存</p></li><li><p>过期</p><ul><li>会在请求头上设置<code>If-Modified-Since</code> 和 <code>If-None-Match</code>询问服务器文件是否有变化，没变化就直接使用，这种方式叫做 <em><strong>协商缓存(304)</strong></em></li></ul><img src="'+i+`"></li></ul></li></ol><ul><li>If-Modified-Since: Tue, 05 Jul 2022 15:09:26 GMT <blockquote><p>这个资源上一次修改时间是格林威治时间 2022-07-05 15:09:26，不知道在这个时间之后有变动吗？</p></blockquote><ul><li>If-None-Match: W/&quot;3be5f29ac3de039909660e93e1ca5912&quot; <blockquote><p>这个资源编号是 W/&quot;3be5f29ac3de039909660e93e1ca5912&quot; ，请问这个资源编号现在发生改变了吗？</p></blockquote></li></ul></li></ul><div class="info custom-block"><p class="custom-block-title">INFO</p><p>总结起来就一句话：你快告诉我这个资源到底变了没？之所以要发这两条消息，是为了兼容不同的服务器，因为有的服务器只认If-Modified-Since，而有的服务器只认If-None-Match，有些两个都认。</p><p>目前有很多服务器，只要发现 <em><strong><code>If-None-Match</code></strong></em> 存在，就不会去看<code>If-Modified-Since</code>，<code>If-Modified-Since</code>是http1.0版本规范，<code>If-None-Match</code>是http1.1的规范</p></div></li></ol><h3 id="cache-control" tabindex="-1">Cache-Control <a class="header-anchor" href="#cache-control" aria-label="Permalink to &quot;Cache-Control&quot;">​</a></h3><p>Cache-Control在上面已经说过了，它是服务器向浏览器响应的一个消息头，它提供了一个max-age用于指定缓存时间。实际上它还有其他值可以选择。</p><ul><li>🚀public：表示服务器资源是公开的，对于浏览器来说并没有什么意义，因为大家看到的东西都是一样的，没有变化，也许在某些场景下有用。</li><li>private：表示服务器资源是私有的，比如某个服务器资源，每个用户看到的都不一样，http协议中很多时候都是客户端或者服务器告诉另一端详细的信息，至于另一端用不用完全自己决定。</li><li>🌵no-cache：这个值看起来字面意思是不缓存的意思😂，其实不然，它会告诉浏览器，你可以缓存这个资源，但是不要直接使用它。当你缓存后，每一次请求都需要附带缓存指令，每一次请求都需要问一下才行，相当于每一次都是协商缓存</li><li>🌵no-store：告诉浏览器不要缓存这个资源，后面每一次请求都按照普通请求进行，</li><li>🚀max-age:这个就不说了吧 😎</li></ul><h2 id="数据格式" tabindex="-1">数据格式 <a class="header-anchor" href="#数据格式" aria-label="Permalink to &quot;数据格式&quot;">​</a></h2><h3 id="post" tabindex="-1">post <a class="header-anchor" href="#post" aria-label="Permalink to &quot;post&quot;">​</a></h3><p>form-data 和 application/x-www-form-urlencoded</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><ul><li>数据包格式的区别，</li><li>数据包中非ANSCII字符怎么编码，是百分号转码发送还是直接发送</li></ul></div><h4 id="application-x-www-form-urlencoded" tabindex="-1">application/x-www-form-urlencoded <a class="header-anchor" href="#application-x-www-form-urlencoded" aria-label="Permalink to &quot;application/x-www-form-urlencoded&quot;">​</a></h4><p>我们可以看出，服务器知道参数用符号&amp;间隔，如果参数值中需要&amp;，则必须对其进行编码。编码格式就是application/x-www-form-urlencoded（将键值对的参数用&amp;连接起来，如果有空格，将空格转换为+加号；有特殊符号，将特殊符号转换为ASCII HEX值）。</p><p>application/x-www-form-urlencoded是 <strong>浏览器默认</strong> 的编码格式。对于Get请求，是将参数转换?key=value&amp;key=value格式，连接到url后</p><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">form</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">action</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">http://localhost:8888/task/</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">method</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">POST</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">First name: </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">firstName</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Mickey&amp;</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;</span><span style="color:#F07178;">br</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">Last name: </span><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">text</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">lastName</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Mouse </span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;&lt;</span><span style="color:#F07178;">br</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">input</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">type</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">submit</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">value</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">提交</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;/</span><span style="color:#F07178;">form</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><img src="`+D+`"><h4 id="form-data" tabindex="-1">form-data <a class="header-anchor" href="#form-data" aria-label="Permalink to &quot;form-data&quot;">​</a></h4><p>multipart/form-data是基于post方法来传递数据的，并且其请求内容格式为Content-Type: multipart/form-data,用来指定请求内容的数据编码格式</p><p>请求体内容各字段之间以--\${boundary}来进行分割,以--\${boundary}--来结束请求体内容</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">POST http://www.example.com HTTP/1.1</span></span>
<span class="line"><span style="color:#A6ACCD;">Content-Type:multipart/form-data; boundary=----WebKitFormBoundaryyb1zYhTI38xpQxBK</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">------WebKitFormBoundaryyb1zYhTI38xpQxBK</span></span>
<span class="line"><span style="color:#A6ACCD;">Content-Disposition: form-data; name=&quot;city_id&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">1</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">------WebKitFormBoundaryyb1zYhTI38xpQxBK</span></span>
<span class="line"><span style="color:#A6ACCD;">Content-Disposition: form-data; name=&quot;company_id&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">2</span></span>
<span class="line"><span style="color:#A6ACCD;">------WebKitFormBoundaryyb1zYhTI38xpQxBK</span></span>
<span class="line"><span style="color:#A6ACCD;">Content-Disposition: form-data; name=&quot;file&quot;; filename=&quot;chrome.png&quot;</span></span>
<span class="line"><span style="color:#A6ACCD;">Content-Type: image/png</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">PNG ... content of chrome.png ...</span></span>
<span class="line"><span style="color:#A6ACCD;">------WebKitFormBoundaryyb1zYhTI38xpQxBK--</span></span></code></pre></div><h5 id="formdata对象" tabindex="-1">FormData对象 <a class="header-anchor" href="#formdata对象" aria-label="Permalink to &quot;FormData对象&quot;">​</a></h5><p>XMLHttpRequest Level 2添加了一个新的接口FormData。利用FormData对象，我们可以通过JavaScript用一些键值对来模拟一系列表单控件，我们还可以使用XMLHttpRequest的send()方法来异步的提交这个&quot;表单&quot;。</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">var</span><span style="color:#A6ACCD;"> formData </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">FormData</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">formData</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">append</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">username</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">Groucho</span><span style="color:#89DDFF;">&quot;</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">formData</span><span style="color:#89DDFF;">.</span><span style="color:#82AAFF;">append</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">accountnum</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">123456</span><span style="color:#A6ACCD;">)</span><span style="color:#89DDFF;">;</span><span style="color:#A6ACCD;"> </span></span>
<span class="line"><span style="color:#82AAFF;">fetch</span><span style="color:#A6ACCD;">(</span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">/users</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">method</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&#39;</span><span style="color:#C3E88D;">POST</span><span style="color:#89DDFF;">&#39;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">body</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> formData</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span></code></pre></div><p>通过fetch进行ajax请求时，会自动为其将其转为form-data格式，无需手动添加格式</p><h2 id="跨域" tabindex="-1"><a href="http://ruanyifeng.com/blog/2016/04/cors.html" target="_blank" rel="noreferrer">跨域</a> <a class="header-anchor" href="#跨域" aria-label="Permalink to &quot;[跨域](http://ruanyifeng.com/blog/2016/04/cors.html)&quot;">​</a></h2><img src="`+y+'">',53),q=s(`<p>浏览器将CORS请求分成两类：简单请求（simple request）和非简单请求（not-so-simple request）</p><p>只要同时满足以下两大条件，就属于简单请求。</p><div class="language-txt"><button title="Copy Code" class="copy"></button><span class="lang">txt</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">(1) 请求方法是以下三种方法之一：</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">- HEAD</span></span>
<span class="line"><span style="color:#A6ACCD;">- GET</span></span>
<span class="line"><span style="color:#A6ACCD;">- POST</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">(2)HTTP的头信息不超出以下几种字段：</span></span>
<span class="line"><span style="color:#A6ACCD;"></span></span>
<span class="line"><span style="color:#A6ACCD;">- Accept</span></span>
<span class="line"><span style="color:#A6ACCD;">- Accept-Language</span></span>
<span class="line"><span style="color:#A6ACCD;">- Content-Language</span></span>
<span class="line"><span style="color:#A6ACCD;">- Last-Event-ID</span></span>
<span class="line"><span style="color:#A6ACCD;">- Content-Type：只限于三个值application/x-www-form-urlencoded、multipart/- form-data、text/plain</span></span></code></pre></div><p>这是为了兼容表单（form），因为历史上表单一直可以发出跨域请求。AJAX 的跨域设计就是，只要表单可以发，AJAX 就可以直接发。</p><p>复杂请求需要发送一个 <strong>预检请求</strong></p><blockquote><p>对于预见请求，其实就是在发送请求之前，浏览器会先去服务器跑一趟，只携带着请求头，询问服务器是否放行，如果服务器同意，则会发送真实请求</p></blockquote><img src="`+F+`"><h3 id="细节" tabindex="-1">细节 <a class="header-anchor" href="#细节" aria-label="Permalink to &quot;细节&quot;">​</a></h3><h4 id="关于cookie" tabindex="-1">- 关于cookie <a class="header-anchor" href="#关于cookie" aria-label="Permalink to &quot;- 关于cookie&quot;">​</a></h4><p>默认情况下，ajax的跨域请求并不会附带cookie</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#676E95;font-style:italic;">// xhr</span></span>
<span class="line"><span style="color:#C792EA;">var</span><span style="color:#A6ACCD;"> xhr </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">new</span><span style="color:#A6ACCD;"> </span><span style="color:#82AAFF;">XMLHttpRequest</span><span style="color:#A6ACCD;">()</span><span style="color:#89DDFF;">;</span></span>
<span class="line"><span style="color:#A6ACCD;">xhr</span><span style="color:#89DDFF;">.</span><span style="color:#A6ACCD;">withCredentials </span><span style="color:#89DDFF;">=</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span><span style="color:#89DDFF;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// fetch api</span></span>
<span class="line"><span style="color:#82AAFF;">fetch</span><span style="color:#A6ACCD;">(url</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#F07178;">credentials</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">include</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span><span style="color:#A6ACCD;">)</span></span></code></pre></div><p>当一个请求需要附带cookie时，无论它是简单请求，还是预检（preflight）请求，都会在请求头中添加cookie字段</p><p>而服务器响应时，需要明确告知客户端：服务器允许这样的凭据</p><p>告知的方式也非常的简单，只需要在响应头中添加：<strong>Access-Control-Allow-Credentials: true</strong> 即可</p><p>对于一个附带身份凭证的请求，若服务器没有明确告知，浏览器仍然视为跨域被拒绝。 另外要特别注意的是：对于附带身份凭证的请求，服务器不得设置 Access-Control-Allow-Origin 的值为*。这就是为什么不推荐使用*****的原因</p><h4 id="关于跨域获取响应头" tabindex="-1">- 关于跨域获取响应头 <a class="header-anchor" href="#关于跨域获取响应头" aria-label="Permalink to &quot;- 关于跨域获取响应头&quot;">​</a></h4><p>在跨域访问时，JS只能拿到一些最基本的响应头，如：Cache-Control、Content-Language、Content-Type、Expires、Last-Modified、Pragma，如果要访问其他头，则需要服务器设置本响应头。</p><p><code>Access-Control-Expose-Headers</code> 头让服务器把允许浏览器访问的头放入白名单，例如 服务器回应的其他CORS相关字段如下:</p><div class="language-js"><button title="Copy Code" class="copy"></button><span class="lang">js</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#A6ACCD;">Access</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Control</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Allow</span><span style="color:#89DDFF;">-</span><span style="color:#FFCB6B;">Methods</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> GET</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> POST</span><span style="color:#89DDFF;">,</span><span style="color:#A6ACCD;"> PUT </span><span style="color:#676E95;font-style:italic;">//</span></span>
<span class="line"><span style="color:#89DDFF;"> </span><span style="color:#676E95;font-style:italic;">// 该字段必需，它的值是逗号分隔的一个字符串，表明服务器支持的所有跨域请求的方法</span></span>
<span class="line"><span style="color:#A6ACCD;">Access</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Control</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Allow</span><span style="color:#89DDFF;">-</span><span style="color:#FFCB6B;">Headers</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> X</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Custom</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Header</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 如果浏览器请求包括Access-Control-Request-Headers字段，</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 则Access-Control-Allow-Headers字段是必需的。它也是一个逗号分隔的字符串，</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 表明服务器支持的所有头信息字段，不限于浏览器在&quot;预检&quot;中请求的字段</span></span>
<span class="line"><span style="color:#A6ACCD;">Access</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Control</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Allow</span><span style="color:#89DDFF;">-</span><span style="color:#FFCB6B;">Credentials</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#FF9CAC;">true</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 该字段与简单请求时的含义相同。</span></span>
<span class="line"><span style="color:#A6ACCD;">Access</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Control</span><span style="color:#89DDFF;">-</span><span style="color:#A6ACCD;">Max</span><span style="color:#89DDFF;">-</span><span style="color:#FFCB6B;">Age</span><span style="color:#89DDFF;">:</span><span style="color:#A6ACCD;"> </span><span style="color:#F78C6C;">1728000</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// 该字段可选，用来指定本次预检请求的有效期，单位为秒。上面结果中，有效期是20天（1728000秒），</span></span>
<span class="line"><span style="color:#89DDFF;"> </span><span style="color:#676E95;font-style:italic;">// 即允许缓存该条回应1728000秒（即20天），在此期间，不用发出另一条预检请求</span></span>
<span class="line"><span style="color:#676E95;font-style:italic;">// Access-Control-Allow-Origin 字段是每次回应都必定包含的</span></span></code></pre></div><h4 id="否定预检请求" tabindex="-1">否定预检请求 <a class="header-anchor" href="#否定预检请求" aria-label="Permalink to &quot;否定预检请求&quot;">​</a></h4><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>如果服务器否定了&quot;预检&quot;请求，会返回一个正常的HTTP回应，但是没有任何CORS相关的头信息字段 这时，浏览器就会认定，服务器不同意预检请求，因此触发一个错误，被XMLHttpRequest对象的 <strong>onerror回调函数</strong>捕获</p></div><h2 id="referrer-policy" tabindex="-1">Referrer-Policy <a class="header-anchor" href="#referrer-policy" aria-label="Permalink to &quot;Referrer-Policy&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>当用户在浏览器上点击一个链接时，会产生一个 HTTP 请求，用于获取新的页面内容，而在该请求的报头中，会包含一个 Referrer，用以指定该请求是从哪个页面跳转页来的，常被用于分析用户来源等信息。</p><p>但是也有成为用户的一个不安全因素，比如有些网站直接将 sessionid 或是 token 放在地址栏里传递的，会原样不动地当作 Referrer 报头的内容传递给第三方网站</p></div><h3 id="指令值" tabindex="-1">指令值 <a class="header-anchor" href="#指令值" aria-label="Permalink to &quot;指令值&quot;">​</a></h3><div class="language-ts"><button title="Copy Code" class="copy"></button><span class="lang">ts</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#C792EA;">enum</span><span style="color:#A6ACCD;"> </span><span style="color:#FFCB6B;">ReferrerPolicy</span><span style="color:#A6ACCD;"> </span><span style="color:#89DDFF;">{</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">no-referrer</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">no-referrer-when-downgrade</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">same-origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">strict-origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">origin-when-cross-origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">strict-origin-when-cross-origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">,</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">unsafe-url</span><span style="color:#89DDFF;">&quot;</span></span>
<span class="line"><span style="color:#89DDFF;">}</span></span></code></pre></div><ul><li><p>no-referrer 整个 Referer 首部会被移除。访问来源信息不随着请求一起发送。</p></li><li><p>no-referrer-when-downgrade（默认值） 在没有指定任何策略的情况下用户代理的默认行为。在同等安全级别的情况下，引用页面的地址会被发送 (HTTPS-&gt;HTTPS)，但是在降级的情况下不会被发送 (HTTPS-&gt;HTTP)。</p></li><li><p>origin 在任何情况下，仅发送文件的源作为引用地址。例如 <a href="https://example.com/page.html" target="_blank" rel="noreferrer">https://example.com/page.html</a> 会将 <a href="https://example.com/" target="_blank" rel="noreferrer">https://example.com/</a> 作为引用地址。</p></li><li><p>origin-when-cross-origin 对于同源的请求，会发送完整的 URL 作为引用地址，但是对于非同源请求仅发送文件的源。</p></li><li><p>same-origin 对于同源的请求会发送引用地址，但是对于非同源请求则不发送引用地址信息。</p></li><li><p>strict-origin 在同等安全级别的情况下，发送文件的源作为引用地址 (HTTPS-&gt;HTTPS)，但是在降级的情况下不会发送 (HTTPS-&gt;HTTP)。</p></li><li><p>strict-origin-when-cross-origin 对于同源的请求，会发送完整的 URL 作为引用地址；在同等安全级别的情况下，发送文件的源作为引用地址 (HTTPS-&gt;HTTPS)；在降级的情况下不发送此首部 (HTTPS-&gt;HTTP)。</p></li><li><p>unsafe-url 无论是同源请求还是非同源请求，都发送完整的 URL（移除参数信息之后）作为引用地址。</p></li></ul><img src="`+C+`"><h3 id="集成到-html" tabindex="-1">集成到 HTML <a class="header-anchor" href="#集成到-html" aria-label="Permalink to &quot;集成到 HTML&quot;">​</a></h3><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">meta</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">name</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">referrer</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">content</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><div class="language-html"><button title="Copy Code" class="copy"></button><span class="lang">html</span><pre class="shiki material-theme-palenight"><code><span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">http://example.com</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">referrerpolicy</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">origin</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span>
<span class="line"><span style="color:#A6ACCD;">  </span><span style="color:#676E95;font-style:italic;">&lt;!-- 或者 --&gt;</span></span>
<span class="line"><span style="color:#89DDFF;">&lt;</span><span style="color:#F07178;">a</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">href</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">http://example.com</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;"> </span><span style="color:#C792EA;">rel</span><span style="color:#89DDFF;">=</span><span style="color:#89DDFF;">&quot;</span><span style="color:#C3E88D;">noreferrer</span><span style="color:#89DDFF;">&quot;</span><span style="color:#89DDFF;">&gt;</span></span></code></pre></div><h2 id="正向代理与-反向代理" tabindex="-1">正向代理与 反向代理 <a class="header-anchor" href="#正向代理与-反向代理" aria-label="Permalink to &quot;正向代理与 反向代理&quot;">​</a></h2><h3 id="正向代理" tabindex="-1">正向代理 <a class="header-anchor" href="#正向代理" aria-label="Permalink to &quot;正向代理&quot;">​</a></h3><blockquote><p>如果你去访问 git 的时候，是访问不了的，你 需要 访问 一台可以 访问 git 的服务器 客户端 去 访问 这个代理服务器 ，代理服务器 去访问 git</p></blockquote><p>客户端知道 要访问的是哪个服务器，服务器 只知道 是哪个 代理的服务器访问的 ，并不知道是哪一个 客户端 访问的 客户端必须设置正向代理服务器，当然前提是要知道正向代理服务器的 IP 地址，还有代理程序的端口</p><h4 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>总结来说：正向代理，&quot;它代理的是客户端&quot;，是一个位于客户端和原始服务器（Origin Server）之间的服务器，为了从原始服务器取得内容，客户端向代理发送一个请求并指定目标（原始服务器）。</p><p>然后代理向原始服务器转交请求并将获得的内容返回给客户端。客户端必须要进行一些特别的设置才能使用正向代理。</p><h4 id="正向代理的用途" tabindex="-1">正向代理的用途 <a class="header-anchor" href="#正向代理的用途" aria-label="Permalink to &quot;正向代理的用途&quot;">​</a></h4><ul><li>访问原来无法访问的资源，如 Google。</li><li>可以做缓存，加速访问资源。</li><li>对客户端访问授权，上网进行认证。</li><li>代理可以记录用户访问记录（上网行为管理），对外隐藏用户信息</li></ul><img src="`+u+'"><h3 id="反向代理" tabindex="-1">反向代理 <a class="header-anchor" href="#反向代理" aria-label="Permalink to &quot;反向代理&quot;">​</a></h3><blockquote><p>我国的某宝网站，每天同时连接到网站的访问人数已经爆表，单个服务器远远不能满足人民日益增长的购买欲望了 出现了分布式部署，通过多台服务器来解决访问人数限制的问题</p></blockquote><h4 id="定义-1" tabindex="-1">定义 <a class="header-anchor" href="#定义-1" aria-label="Permalink to &quot;定义&quot;">​</a></h4><p>多个客户端给服务器发送的请求，Nginx 服务器接收到之后，按照一定的规则分发给了后端的业务处理服务器进行处理了 此时请求的来源也就是客户端是明确的，但是请求具体由哪台服务器处理的并不明确了，Nginx 扮演的就是一个反向代理角色。</p><p>反向代理，<strong>&quot;它代理的是服务端&quot;</strong>，主要用于服务器集群分布式部署的情况下，反向代理隐藏了服务器的信息。</p><h4 id="反向代理的作用" tabindex="-1">反向代理的作用 <a class="header-anchor" href="#反向代理的作用" aria-label="Permalink to &quot;反向代理的作用&quot;">​</a></h4><ul><li>保证内网的安全，通常将反向代理作为公网访问地址，Web 服务器是内网。</li><li>负载均衡，通过反向代理服务器来优化网站的负载。</li></ul><img src="'+d+'"><h3 id="负载均衡" tabindex="-1">负载均衡 <a class="header-anchor" href="#负载均衡" aria-label="Permalink to &quot;负载均衡&quot;">​</a></h3><p>这里提到的客户端发送的、Nginx 反向代理服务器接收到的请求数量，就是我们说的负载量。请求数量按照一定的规则进行分发，到不同的服务器处理的规则，就是一种均衡规则。 所以将服务器接收到的请求按照规则分发的过程，称为负载均衡。</p><h2 id="网络攻击" tabindex="-1">网络攻击 <a class="header-anchor" href="#网络攻击" aria-label="Permalink to &quot;网络攻击&quot;">​</a></h2><h3 id="xss" tabindex="-1">xss <a class="header-anchor" href="#xss" aria-label="Permalink to &quot;xss&quot;">​</a></h3><p><strong>cross site script(跨站点脚本)</strong> 将 js 脚本插入到 网页内容中，渲染时执行 js 脚本 方法： 替换特殊字符</p><h3 id="csrf" tabindex="-1">csrf <a class="header-anchor" href="#csrf" aria-label="Permalink to &quot;csrf&quot;">​</a></h3><p>cross site request forgery(跨站请求伪造)</p><p>诱导用户请求另一个网站 有一个a 网站，点击按钮 到 b 网站，在 b 网站的时候 ，并发起 a 网站的请求，a 网站会以为是用户自己发起的 比如：一个 gmail 网站，点击按钮到 b网站，在b网站中 转发邮件，由于 带了 a 网站的 cookie ，所以可以执行 方法：预防 跨域 sameSite，验证码，referrer</p><h3 id="click-jacking-点击劫持" tabindex="-1">click jacking 点击劫持 <a class="header-anchor" href="#click-jacking-点击劫持" aria-label="Permalink to &quot;click jacking 点击劫持&quot;">​</a></h3><p>界面上蒙了一层透明的 iframe，诱导去点击 <img src="'+A+'"></p>',58);function g(b,f,k,T,x,P){return l(),n("div",null,[m,o(" :::danger 虽然跨域，但是服务器依然可以收发响应，只是浏览器拦截 ::: "),q])}const S=a(h,[["render",g]]);export{_ as __pageData,S as default};
